sql:
SELECT property_id, agent_id
FROM appointments
WHERE appointment_status = 'completed';

external_knowledge:
- 'On the market' refers to properties with an active listing status;
- 'Last year' refers to the past 12 months from the current date;
- 'Property types' include categories like single-family homes, condos, and others.

sql:
SELECT DISTINCT f.property_id
FROM feedback f
WHERE f.feedback_date >= DATE('now', '-30 days');

SELECT agent_name
FROM agents
ORDER BY years_of_experience DESC;

external_knowledge:
- "boats" metaphorically refers to properties; 
- "waters" represent the various listing statuses; 
- "number of boats" corresponds to the count of properties; 
- "average value these boats represent" refers to the average median house value; 
- "how long they've been adrift" signifies the average days on the market.

sql:
SELECT agent_name, years_of_experience 
FROM agents 
WHERE years_of_experience = (SELECT MAX(years_of_experience) FROM agents);

SELECT property_id, COUNT(*) AS total_appointments
FROM appointments
GROUP BY property_id;
